      <div className="mt-8 space-y-6">
        {projects.map((project) => {
          const rubric = project.humanReviewRubric!;
          const workflow = (project.workflow ?? "gad") as Workflow;
          const exampleJson = buildExampleJson(rubric.dimensions);
          return (
            <div
