/**
 * Tiny frontmatter parser. Handles the `---\n...\n---\n<body>` shape.
 * Returns { data, body }. Only understands key: value (strings, one level).
 */
function parseFrontmatter(src) {
  if (!src.startsWith("---")) return { data: {}, body: src };
