    const line = rawLine;
    const m = line.match(/^([A-Za-z0-9_-]+):\s*(.*)$/);
    if (m && !/^\s/.test(rawLine)) {
      if (key) data[key] = buf.trim();
      key = m[1];
      buf = m[2];
    } else if (key) {
